#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_lq.zw;
vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5)*uAspect.xy;

vec2 uv6=sin(23*vUv);
float dots = .001/length(uv6)*q1*q1;


vec2 zz = vUv.xy * uTexSize.xy *.04;
float h1 = (cos(zz.y*q1) * sin(-zz.y));
float h2 = (sin(zz.x) * cos(zz.y*q2));

vUv.xy -= vec2(h1,h2)*uTexSize.zw * 24*q28;

vec3 crisp = 1*GetPixel(vUv) + .0*lum(GetPixel(vUv));
ret = crisp*.99 -.006;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 hor = vec2(uTexSize.z,0);
vec2 ver = vec2(0,uTexSize.w);

uv5 = vUv;
uv1 = vUv-0.5;
uv1 *= uAspect.xy;
dz = 0;
float dist = 1;
float inten = 1;
float mask = 0;
ret1 = 0;
int anz = 3;
float n = 0;
while (n <= anz) {
    dist = 1-fract(1.0/anz*n+q29); //evtl sqrt !;
    inten =  (dist)*(1-dist*dist)*4;

//dist *= dist ;

    uv3 = 2*uv1*dist + vec2(q30,.5);
uv3 *= uAspect.yx;
    neu = GetPixel(uv3);
    dz.x += inten*lum(GetPixel(uv3+hor)- GetPixel (uv3-hor));
    dz.y += inten*lum(GetPixel(uv3+ver)- GetPixel (uv3-ver));
    ret1 = max(ret1,neu*inten);
n++;
}

//sun
uv1 += dz/2;
uv4 = sin(3*uv1+uTime/18*vec2(1,.9));
float k1 = texture(sampler_noise_lq,vUv);
sun = clamp01(4*(.25-uv1.y)) * .3/length(uv4) ;
sun *= .5+.5*rand_preset*vec3(1,1,.3);

vec3 sky = vec3 (vUv.y,.2,1.5-vUv.y);
sky = sun * (.5+sky);

//tree
k1 = .5*(rand_preset-.5);
uv3 = 150 * (uv1-vec2(k1,.05)) + dz;

float zu = .3*lum(texture(sampler_noise_lq,vUv));
float ky = clamp01(-.01*uv3.y+zu*cos(12*zu));

k1 = uv3.x*(1);;
k1 = k1 - sign (k1)*16; //Verdoppelung

n = 1 ;
while (n <= 5)
{
  k1 += 2*(k1-6*n*sign(k1))*ky;
  ky = clamp01(ky -.08);
  n++;
}

k1 = clamp(k1,-1.6,1.6);

vec3 tree = 2*abs(cos(k1))*pow(vUv.y,2);

ret = .1+.4*rand_preset.x*ret1 + clamp01(sky - tree);
//ret = GetPixel(uv5);

  fragColor = ret;
}
